import{_ as e,c as t,o as a,b as o}from"./app.f442ac1c.js";const u='{"title":"Chords","description":"","frontmatter":{"title":"Chords","subtitle":"Three and more note collections","date":"2021-09-25T00:00:00.000Z"},"headers":[],"relativePath":"apps/chord/index.md"}',r={},s=o('<p>There are thousands of possible 3-5 notes combinations, that are used as chords in modern music. You can find the shapes for the most used of them with the simple <a href="./finder/">Chord finder</a>. Select a chord type and then click on the desired pitch on the virtual keyboard. If you need the get the shape of chords on a string instument - try the <a href="./tabs/">Chord Tabs app</a>.</p><p>To navigate the multitude of chord combinations and sequences you can explore their <a href="./modes/">Modal functions</a> in different scales. The relations between chords really shine in multiaxis interpretations like the Tonnetz <a href="./array/">Tonal array</a> or the interactive <a href="./fifths/">Circle of fifths</a> chords wheel.</p>',2),n=[s];function i(h,d,c,f,l,_){return a(),t("div",null,n)}var m=e(r,[["render",i]]);export{u as __pageData,m as default};
